#include<bits/stdc++.h>
using namespace std;
const int maxi=1e2+5;
int n;
bool flag[maxi];
int a[maxi],b[maxi];
long long cnt;
bool cmp(int a,int b){
	return a>b;
}
void calc(int x){
	if(x==n+1){
		cnt++;
		return ;
	}
	for(int i=1;i<=n;i++){
		if(flag[i]||a[i]>b[x])continue;
		flag[i]=1;
		calc(x+1);
		flag[i]=0;
	}
}
int main()
{
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>a[i];
	}
	for(int i=0;i<n;i++){
		cin>>b[i];
	}
	cnt=1;
	sort(&a[0],&a[n],cmp);
	sort(&b[0],&b[n],cmp);
	for(int i=0;i<n;i++){
		int shu=0;
		for(int j=0;j<n;j++){
			if(a[i]>b[j]){
//				cout<<i<<" "<<j<<endl;
				break;
			}
			else{
				
				shu++;
			}
		}
		shu-=i;
//		cout<<shu<<endl<<i<<"/"<<endl;
		cnt*=shu;
	}
	cout<<cnt;
	return 0;
}
